mapper.select:
/** CmmtHldyExclDao.selectList */
select

from
	cmmt_hldy_excl
where
	substring(ymd, 1, 4) = #{year}

		and ymd_nm = #{ymdNm}

mapper.insert:
/** CmmtHldyExclDao.insert */
insert into cmmt_hldy_excl (
	 ymd
	,ymd_nm
	,excl_reason
) values (
	 #{ymd}
	,#{ymdNm}
	,#{exclReason}
)

mapper.select:
/** CmmtHldyExclDao.select */
select

	from
		cmmt_hldy_excl
	where
		ymd = #{ymd}

mapper.update:
/** CmmtHldyExclDao.update */
update cmmt_hldy_excl set
	 ymd 		= #{ymd}
	,ymd_nm 	= #{ymdNm}
	,excl_reason  = #{exclReason}
where
	ymd = #{ymd}

mapper.insert:
/** CmmtHldyExclDao.delete */
delete from
	cmmt_hldy_excl
where
	ymd = #{ymd}
